-- ------------------------------------------------------------
-- Phase 2a: Allow company admins to create user_actions for users in their company
-- (needed for Deploy & Enrol - package assignment)

CREATE POLICY "Admin insert user_actions for company users" ON public.user_actions
  FOR INSERT WITH CHECK (
    EXISTS (SELECT 1 FROM public.profiles pr WHERE pr.id = auth.uid() AND pr.role = 'superadmin')
    OR user_id IN (
      SELECT p.id FROM public.profiles p
      WHERE p.company_id = (SELECT pr.company_id FROM public.profiles pr WHERE pr.id = auth.uid() AND pr.role = 'admin' LIMIT 1)
    )
  );

CREATE POLICY "Admin update user_actions for company users" ON public.user_actions
  FOR UPDATE USING (
    EXISTS (SELECT 1 FROM public.profiles pr WHERE pr.id = auth.uid() AND pr.role = 'superadmin')
    OR user_id IN (
      SELECT p.id FROM public.profiles p
      WHERE p.company_id = (SELECT pr.company_id FROM public.profiles pr WHERE pr.id = auth.uid() AND pr.role = 'admin' LIMIT 1)
    )
  );

-- ------------------------------------------------------------
-- Source: supabase/migrations/008_profiles_policy_recursion_fix.sql
-- ------------------------------------------------------------
-- Fix: infinite recursion in profiles RLS policies.
-- Policies that SELECT from profiles while evaluating access to profiles cause recursion.
-- Use SECURITY DEFINER functions so role/company_id are read without triggering RLS.

CREATE OR REPLACE FUNCTION public.current_user_role()
RETURNS TEXT
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT role FROM public.profiles WHERE id = auth.uid() LIMIT 1;
$$;

CREATE OR REPLACE FUNCTION public.current_user_company_id()
RETURNS UUID
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT company_id FROM public.profiles WHERE id = auth.uid() LIMIT 1;
$$;

-- Replace policies that query profiles (causing recursion) with function-based checks
DROP POLICY IF EXISTS "Superadmin update any profile" ON public.profiles;
CREATE POLICY "Superadmin update any profile" ON public.profiles
  FOR UPDATE USING (public.current_user_role() = 'superadmin');

DROP POLICY IF EXISTS "Company admin read company profiles" ON public.profiles;
CREATE POLICY "Company admin read company profiles" ON public.profiles
  FOR SELECT USING (
    company_id IS NOT NULL
    AND company_id = public.current_user_company_id()
    AND public.current_user_role() IN ('admin', 'superadmin')
  );

-- ------------------------------------------------------------
-- Source: supabase/migrations/009_user_actions_accepted_at.sql
-- ------------------------------------------------------------
-- Add accepted_at to user_actions: when user committed (with or without a specific schedule).
-- - When user picks date/time: scheduled_at = that time, accepted_at = now().
-- - When user "accepts" without time (do whenever): scheduled_at = null, accepted_at = now().
-- Validation queue shows "Scheduled for xyz" vs "Accepted on xyz" using these.

ALTER TABLE public.user_actions
  ADD COLUMN IF NOT EXISTS accepted_at TIMESTAMPTZ;

COMMENT ON COLUMN public.user_actions.accepted_at IS 'When the user committed to this action (plan or accept without schedule).';

