-- Source: supabase/migrations/010_package_actions_delivery_date.sql
-- ------------------------------------------------------------
-- Add per-action (per-week) delivery dates for packages
-- This lets admins control exactly when each week's delivery goes live.

ALTER TABLE public.package_actions
ADD COLUMN IF NOT EXISTS delivery_date DATE;


-- ------------------------------------------------------------
-- Source: supabase/migrations/011_package_actions_delivery_time.sql
-- ------------------------------------------------------------
-- Add per-action (per-delivery) time of day for packages
-- This lets each delivery within a package have its own delivery_time.

ALTER TABLE public.package_actions
ADD COLUMN IF NOT EXISTS delivery_time TIME;


-- ------------------------------------------------------------
-- Source: supabase/migrations/012_habit_occurrences.sql
-- ------------------------------------------------------------
-- Habit loop: store committed rep dates (daily sprint = next 4 days; weekly = same weekday next 4 weeks).
-- Used to show "scheduled for Feb 10" etc. in the queue and to drive reminders.

CREATE TABLE IF NOT EXISTS public.habit_occurrences (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  user_id UUID REFERENCES public.profiles(id) ON DELETE CASCADE NOT NULL,
  action_id UUID REFERENCES public.actions(id) ON DELETE CASCADE NOT NULL,
  user_action_id UUID REFERENCES public.user_actions(id) ON DELETE CASCADE NOT NULL,
  scheduled_at TIMESTAMPTZ NOT NULL,
  completed_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_habit_occurrences_user_action
  ON public.habit_occurrences(user_action_id);
CREATE INDEX IF NOT EXISTS idx_habit_occurrences_user_scheduled
  ON public.habit_occurrences(user_id, scheduled_at);

ALTER TABLE public.habit_occurrences ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Users CRUD own habit_occurrences" ON public.habit_occurrences
  FOR ALL USING (auth.uid() = user_id);

COMMENT ON TABLE public.habit_occurrences IS 'Committed rep dates for habit loop (Rule of 5). Daily = next 4 days; Weekly = same weekday next 4 weeks.';

-- ------------------------------------------------------------
-- Source: supabase/migrations/013_auto_login_infrastructure.sql
-- ------------------------------------------------------------
-- Auto-login infrastructure: persistent keys + logging
-- NO email sending; internal preparation only.

-- 1. Add persistent_login_key to profiles
ALTER TABLE public.profiles
  ADD COLUMN IF NOT EXISTS persistent_login_key UUID UNIQUE;

-- 2. Create index for fast key lookups
CREATE INDEX IF NOT EXISTS idx_profiles_persistent_login_key
  ON public.profiles(persistent_login_key)
  WHERE persistent_login_key IS NOT NULL;

-- 3. Create auto_login_logs table for security audit
CREATE TABLE IF NOT EXISTS public.auto_login_logs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID REFERENCES auth.users(id) ON DELETE SET NULL,
  ip_address TEXT,
  user_agent TEXT,
  success BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_auto_login_logs_user_id
  ON public.auto_login_logs(user_id);
CREATE INDEX IF NOT EXISTS idx_auto_login_logs_created_at
  ON public.auto_login_logs(created_at DESC);

-- RLS: service role only (no direct client access)
ALTER TABLE public.auto_login_logs ENABLE ROW LEVEL SECURITY;

-- No SELECT policy for anon/authenticated - only service role can read/write
CREATE POLICY "Service role only auto_login_logs" ON public.auto_login_logs
  FOR ALL USING (false) WITH CHECK (false);

COMMENT ON TABLE public.auto_login_logs IS 'Audit log for auto-login attempts. Accessible only via service role.';
COMMENT ON COLUMN public.profiles.persistent_login_key IS 'UUID used for persistent auto-login links. Rotate via admin when needed.';

-- ------------------------------------------------------------
-- Source: supabase/migrations/014_auto_login_backfill_and_trigger.sql
-- ------------------------------------------------------------
-- Backfill persistent_login_key for existing users
-- and update trigger so new users get a key automatically

-- 1. Backfill: create profiles for any auth.users that don't have one (edge case)
INSERT INTO public.profiles (id, persistent_login_key)
SELECT id, gen_random_uuid()
FROM auth.users
ON CONFLICT (id) DO NOTHING;

-- 2. Backfill: assign key to all existing profiles that don't have one
UPDATE public.profiles
SET persistent_login_key = gen_random_uuid()
WHERE persistent_login_key IS NULL;

-- 3. Update handle_new_user to set persistent_login_key for new signups
CREATE OR REPLACE FUNCTION public.handle_new_user()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.profiles (id, full_name, avatar_url, company_id, role, persistent_login_key)
  VALUES (
    NEW.id,
    NEW.raw_user_meta_data->>'full_name',
    NEW.raw_user_meta_data->>'avatar_url',
    NULL,
    'user',
    gen_random_uuid()
  );
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER;

